VALUES
  ('aboriginal-64311456-moex-00177', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依司法院解釋意旨，退休人員再任私立學校職務且每月支領薪酬總額超過法定基本工資，停止領受月 退休金權利之規定，牴觸下列何者基本權利？', '["平等權", "工作權", "財產權", "生存權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00178', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '關於憲法上規定人民「服兵役」的義務，下列敘述何者正確？', '["人民得因信仰宗教而拒絕服兵役", "兵役法規定，中華民國男子依法皆有服兵役之義務；然如修改兵役法規定女子要服兵役，並不違憲", "妨害兵役治罪條例規定後備軍人居住處所遷移，無故不依規定申報者處以刑事罰，此侵害人民居住 遷徙自由而屬違憲", "法律如對義務役士兵訂有不同之服役期限及地點規定，違反平等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00179', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依司法院大法官解釋，關於憲法非明文規定之自由權利，下列敘述何者錯誤？', '["相同性別二人為經營共同生活之目的，成立親密性及排他性之永久結合關係，受婚姻自由保障", "社會秩序維護法有關跟追之限制規定，干預新聞採訪自由，違憲", "收養行為攸關收養人與被收養人間合意，屬憲法第22條保障之收養自由", "一般行為自由包括使用交通工具的自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00180', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '各級學校學生認其權利因學校之教育或管理等公權力措施而遭受侵害時，關於其救濟，依司法院大法 官解釋之意旨，下列敘述何者錯誤？', '["學生因學校之退學處分，改變其學生身分並損及其受教育之機會，依法得提起訴願及行政訴訟", "學校對學生所為之處分若未侵害學生受教育之權利，則學生僅能循學校內部申訴途徑救濟，不得提 起行政爭訟", "學校對學生所為之管理措施如屬顯然輕微之干預，則難謂構成權利之侵害", "學生對於學校之管理措施提起行政救濟時，法院及行政爭訟機關應尊重學校之專業判斷餘地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00181', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '總統發布下列何種命令前，毋須經行政院會議決議？', '["宣布戒嚴", "發布大赦令", "發布緊急命令", "宣告解散立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00182', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依憲法增修條文規定，有關總統、副總統之選舉與罷免，下列敘述何者錯誤？', '["總統、副總統由中華民國自由地區全體人民直接選舉之", "總統、副總統之罷免案，經立法院同意後提出，並經中華民國自由地區選舉人總額過半數之投票， 有效票過半數同意罷免時，即為通過", "總統、副總統候選人應聯名登記，在選票上同列一組圈選，以得票最多之一組為當選", "總統、副總統之罷免案，須經全體立法委員3分之1之提議，並經全體立法委員3分之2同意提出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00183', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '關於政黨違憲解散案件之審理，下列敘述何者正確？', '["由司法院大法官組成憲法法庭審理之，並由參與案件審理之資深大法官擔任審判長", "政黨之目的或其行為，危害中華民國之存在或自由民主之憲政秩序者，由內政部聲請憲法法庭為宣 告政黨解散之判決", "宣告政黨解散之判決，其評決應經大法官現有總額2分之1以上同意；評決未達前項同意人數時， 應為不予解散之判決", "經憲法法庭宣告解散之政黨，其依政黨比例方式產生之立法委員，自憲法法庭判決生效日或主管機 關為解散公告日起之第3日，喪失其資格"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00184', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '有關釋憲聲請案之審理，下列敘述何者錯誤？', '["對學生所為之學習評量、其他管理、獎懲措施等措施，法院應尊重教師及學校本於專業及對事實真 象之熟知所為之決定，僅於其判斷或裁量違法或顯然不當時，得予撤銷或變更", "立法機關就各種社會給付之優先順序、規範目的、受益人範圍、給付方式及額度等項之有關規定， 自享有充分之形成自由，司法院大法官解釋對之向來採取較寬鬆之審查基準", "國家領土之範圍如何界定，純屬政治問題；其界定之行為，依權力分立之憲政原則，不受司法審查", "修改憲法亦係憲法上行為之一種，縱有重大明顯瑕疵，依權力分立之憲政原則，不受司法審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00185', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '財政與稅收自主為地方自治的內涵之一，從既有司法院大法官解釋之內涵觀之，下列敘述何者錯誤？', '["法律實施須由地方負擔經費時，因為法律之制定，無待地方參與，由立法院制定即可", "地方可以獨立管理並使用地方財產", "地方施政所需之經費負擔有法律保留原則之適用", "對地方負有協力義務之事項，中央依據法律可使地方分擔一定費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00186', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '關於立法院職權之敘述，下列何者正確？', '["依憲法本文規定由監察院行使之人事同意權，依據憲法增修條文之規定，已改由立法院行使", "立法院對於各機關所編列預算之數額，得在款項目節間移動增減並追加或削減原預算之項目", "依據憲法本文之規定，立法院遇有立法委員五分之一以上之請求，得開臨時會", "依憲法增修條文之規定，立法院對總統之罷免案，須經全體立法委員至少二分之一以上之提議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:08+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
